import express = require("express");
import OAuth2Server = require("oauth2-server");

declare namespace ExpressOAuthServer {
    interface Options extends OAuth2Server.ServerOptions {
        useErrorHandler?: boolean | undefined;
        continueMiddleware?: boolean | undefined;
    }
}

declare class ExpressOAuthServer {
    server: OAuth2Server;

    constructor(options: ExpressOAuthServer.Options);

    authenticate(options?: OAuth2Server.AuthenticateOptions): (
        request: express.Request,
        response: express.Response,
        next: express.NextFunction,
    ) => Promise<OAuth2Server.Token>;

    authorize(options?: OAuth2Server.AuthorizeOptions): (
        request: express.Request,
        response: express.Response,
        next: express.NextFunction,
    ) => Promise<OAuth2Server.AuthorizationCode>;

    token(options?: OAuth2Server.TokenOptions): (
        request: express.Request,
        response: express.Response,
        next: express.NextFunction,
    ) => Promise<OAuth2Server.Token>;
}

export = ExpressOAuthServer;

import type { OutgoingHttpHeaders } from 'node:http';

import { StatusCodes } from 'http-status-codes';

import { HttpContent } from './content/httpContent';

const MAX_STATUS_CODE: number = 999;

export class HttpResponseMessage {
  private _content!: HttpContent;

  private _headers: OutgoingHttpHeaders = {};

  private _statusCode!: number;

  constructor(statusCode: number = StatusCodes.OK) {
    this.statusCode = statusCode;
  }

  public get content(): HttpContent {
    return this._content;
  }

  public get headers(): OutgoingHttpHeaders {
    return this._headers;
  }

  public get statusCode(): number {
    return this._statusCode;
  }

  public set content(value: HttpContent) {
    this._content = value;
  }

  public set headers(headers: OutgoingHttpHeaders) {
    this._headers = headers;
  }

  public set statusCode(code: number) {
    if (code < 0 || code > MAX_STATUS_CODE) {
      throw new Error(`${code.toString()} is not a valid status code`);
    }

    this._statusCode = code;
  }
}

import type { spawn } from "child_process";
import type { Application, Handler } from "express";
import type { createServer } from "https";

declare namespace gls {
    interface LivereloadParams {
        livereload?: string;
        port?: number;
        errorListener?: (error: Error) => void;
        handler?: Handler;
        app?: Application;
        key?: NonNullable<Parameters<typeof createServer>[0]>["key"];
        cert?: NonNullable<Parameters<typeof createServer>[0]>["cert"];
        pfx?: NonNullable<Parameters<typeof createServer>[0]>["pfx"];
        liveCSS?: boolean;
        liveImg?: boolean;
        prefix?: boolean;
        dashboard?: boolean;
    }
    type Livereload = boolean | number | LivereloadParams;

    interface GLSStatic {
        start: (execPath?: string) => void;
        notify: (event: { path: string }) => void;
        stop: () => void;
        static: (folder: string, port?: number) => GLSStatic;
        new: (script: string) => GLSStatic;
    }

    type GLS = {
        (args: Parameters<typeof spawn>[1], options?: Parameters<typeof spawn>[2], livereload?: Livereload): GLSStatic;
    } & GLSStatic;
}

declare var gls: gls.GLS;
export = gls;
